module top_module(
    input  wire        clk,
    input  wire        clr,
    input  wire [ 7:0] A,
    input  wire [ 7:0] B,
    output reg  [15:0] Z
);reg [15:0] accumulator;

    always @(posedge clk) begin
        if (clr) begin
            accumulator <= 0;
        end else begin
            accumulator <= A * B;
        end
    end

    assign Z = accumulator;

endmodule
